import requests

def audit_managed_identities(token: str, subscription_id: str) -> list:
    """List all user-assigned MIs in a subscription with their assignments."""
    HDR = {"Authorization": f"Bearer {token}"}

    # List all user-assigned MIs via ARM
    mis = requests.get(
        f"https://management.azure.com/subscriptions/{subscription_id}/providers/Microsoft.ManagedIdentity/userAssignedIdentities",
        headers=HDR,
        params={"api-version": "2023-01-31"}
    ).json().get("value", [])

    report = []
    for mi in mis:
        principal_id = mi["properties"]["principalId"]

        # Find role assignments for this MI across the subscription
        assignments = requests.get(
            f"https://management.azure.com/subscriptions/{subscription_id}/providers/Microsoft.Authorization/roleAssignments",
            headers=HDR,
            params={"api-version": "2022-04-01", "$filter": f"principalId eq '{principal_id}'"}
        ).json().get("value", [])

        report.append({
            "name": mi["name"],
            "resource_group": mi["id"].split("/")[4],
            "client_id": mi["properties"]["clientId"],
            "role_assignment_count": len(assignments),
            "roles": [a["properties"].get("roleDefinitionId","").split("/")[-1] for a in assignments]
        })

    return sorted(report, key=lambda x: x["role_assignment_count"], reverse=True)

